	.SBTTL	PRICOMM;--------\; EDICOMM >;========/; Edite le format d'une page.; in	-; out	D7.W	erreur; mod	D7.WEDICOMM:	PUSHM.L	D3,D4,D5,A3	LOAD.W	(A6)+ONOSEL,#CASDEF ; slectionne case marge de gauche	CALL	RSTPRINT	; lit le status de l'imprimante	JUMP,NE	95$	CALL	INIPRINT	; init l'chelle	CALL	OPEPRINT	; init variables pour dessin	CALL	AFTINFO		; affiche textes des infos	CALL	AFINFO		; affiche qq renseignements	CALL	AFPEXT		; affiche la page	CALL	AFPINT		; affiche surface dans page	LOAD.L	A3,#R16"TXMEN1	.W	LIB,?AFMENU20$:	.W	LIB,?GETKEY	; attend clavier/souris ...	TEST.L	D3:#BKPSEUDO	; pseudo code/touche relache ?	JUMP,BS	20$		; oui => 20$	CLR.W	D7		; D7 <-- ok	COMP.B	D3,#END	JUMP,EQ	90$	COMP.B	D3,#F0	JUMP,EQ	90$	COMP.B	D3,#F0+SHIFT	JUMP,EQ	90$	COMP.W	D3,#KEYMGP	; bouton souris press ?	JUMP,EQ	30$	COMP.W	D3,#KEYMMP	; bouton souris press ?	JUMP,EQ	30$	COMP.W	D3,#KEYMDP	; bouton souris press ?	JUMP,EQ	30$	COMP.W	D3,#KEYMPO	; souris bouge ?	JUMP,EQ	20$	CALL	EXFLECHE	JUMP,NE	80$	JUMP	20$30$:	.W	LIB,?IFMOUSE	; D4 <-- position souris	CALL	DETECTE		; D0 <-- dtecte que dplacer	JUMP,NE	80$	COMP.B	D0,#-1		; slection d'une case ?	JUMP,EQ	40$		; oui => 40$	JUMP	36$		; non => modifie tout de suite la page35$:	.W	LIB,?GETKEY	; attend clavier/souris ...	TEST.L	D3:#BKPSEUDO	; pseudo code/touche relache ?	JUMP,BS	35$		; oui => 35$	COMP.W	D3,#KEYMGR	; bouton souris relach ?	JUMP,EQ	38$		; oui => 38$	COMP.W	D3,#KEYMMR	; bouton souris relach ?	JUMP,EQ	38$		; oui => 38$	COMP.W	D3,#KEYMDR	; bouton souris relach ?	JUMP,EQ	38$		; oui => 38$	COMP.W	D3,#KEYMPO	; souris dplace ?	JUMP,NE	35$		; non => 35$36$:	.W	LIB,?IFMOUSE	; D4 <-- position souris	CALL	MODIF		; modifie la page	PUSH.W	D7	CALL	AFQINT		; r-affiche rapidement	POP.W	D7	JUMP,EQ	35$	LOAD.B	D3,#BIPLIT	.W	LIB,?BEEP	; p'tit bruit	JUMP	35$38$:	CALL	CLOPRINT	; mj status de l'imprimante	CALL	AFPINT		; affiche la surface intrieure	CALL	AFINFO		; affiche les infos	JUMP	20$40$:	CALL	AFINFO		; montre la case slectionne	LOAD.W	D5,(A6)+ONOSEL	; D5 <-- no case slectionne42$:	.W	LIB,?GETKEY	; attend clavier/souris ...	TEST.L	D3:#BKPSEUDO	; pseudo code/touche relache ?	JUMP,BS	42$		; oui => 42$	COMP.W	D3,#KEYMGR	; bouton souris relach ?	JUMP,EQ	20$		; oui => 20$	COMP.W	D3,#KEYMMR	; bouton souris relach ?	JUMP,EQ	20$		; oui => 20$	COMP.W	D3,#KEYMDR	; bouton souris relach ?	JUMP,EQ	20$		; oui => 20$	COMP.W	D3,#KEYMPO	; souris dplace ?	JUMP,NE	42$		; non => 42$				; oui =>	.W	LIB,?IFMOUSE	; D4 <-- position souris	CALL	DETECTE		; D0 <-- dtecte que dplacer	JUMP,NE	42$	COMP.B	D0,#-1		; slection d'une case ?	JUMP,NE	42$		; non => 42$	COMP.W	D5,(A6)+ONOSEL	; mme case slectionne ?	JUMP,EQ	42$		; oui => 42$	JUMP	40$80$:	LOAD.B	D3,#BIPLIT	.W	LIB,?BEEP	; p'tit bruit	JUMP	20$90$:	CALL	DBOXMAJ		; demande si mise  jour ?	JUMP,EQ	91$		; oui => 91$	CLR.W	D7	JUMP	92$91$:	CALL	WSTPRINT	; crit le status dans l'imprimante92$:	PUSH.W	D7	LOAD.W	D5,(A6)+ONOWDT	.W	LIB,?USEWDO	; utilise swdo texte	LOAD.L	A3,#R16"TXMENU	.W	LIB,?AFMENU	; remet un menu "neutre"	POP.W	D795$:	POPM.L	D3,D4,D5,A3	TEST.W	D7		; retour EQ/NE	RET;---------\; EXFLECHE >;=========/; Excute une modification de la page selon le clavier.; in	D3.W	touche presse; out	D7.W	erreur; mod	D7.WEXFLECHE:	PUSHM.L	D3,D4,D5	.W	LIB,?MINMAJ	; D3 <-- lettre MAJUSCULE	COMP.B	D3,#CR	JUMP,EQ	40$	COMP.B	D3,#ENTER	JUMP,EQ	40$	COMP.W	D3,#H'100*(2^BCURSOR)+'R	JUMP,EQ	30$	COMP.B	D3,#F4	JUMP,EQ	30$	COMP.B	D3,#F4+SHIFT	JUMP,EQ	30$	COMP.B	D3,#F5	JUMP,EQ	30$	COMP.B	D3,#F5+SHIFT	JUMP,EQ	30$	COMP.B	D3,#F6	JUMP,EQ	30$	COMP.B	D3,#F6+SHIFT	JUMP,EQ	30$	COMP.W	D3,#H'100*(2^BCURSOR)+'C	JUMP,EQ	35$	COMP.B	D3,#F1	JUMP,EQ	35$	COMP.B	D3,#F1+SHIFT	JUMP,EQ	35$	COMP.B	D3,#F2	JUMP,EQ	35$	COMP.B	D3,#F2+SHIFT	JUMP,EQ	35$	COMP.B	D3,#F3	JUMP,EQ	35$	COMP.B	D3,#F3+SHIFT	JUMP,EQ	35$	COMP.W	D3,#H'100*(2^BCURSOR)+'D	JUMP,EQ	50$	COMP.B	D3,#F10	JUMP,EQ	50$	COMP.B	D3,#F10+SHIFT	JUMP,EQ	50$	COMP.B	D3,#F11	JUMP,EQ	50$	COMP.B	D3,#F11+SHIFT	JUMP,EQ	50$	COMP.B	D3,#F12	JUMP,EQ	50$	COMP.B	D3,#F12+SHIFT	JUMP,EQ	50$	COMP.W	D3,#H'100*(2^BCURSOR)+'F	JUMP,EQ	60$	COMP.B	D3,#F13	JUMP,EQ	60$	COMP.B	D3,#F13+SHIFT	JUMP,EQ	60$	COMP.B	D3,#F14	JUMP,EQ	60$	COMP.B	D3,#F14+SHIFT	JUMP,EQ	60$	COMP.B	D3,#F15	JUMP,EQ	60$	COMP.B	D3,#F15+SHIFT	JUMP,EQ	60$	LOAD.W	D7,#1	TEST.L	D3:#7		; touche spciale ?	JUMP,BS	90$		; oui => 90$	LOAD.W	D5,(A6)+ONOSEL	; D5 <-- no de la case	CALL	ASKSEL		; modifie cette case	CLR.W	D7	JUMP	90$30$:				; MONTE =>	TEST.W	(A6)+ONOSEL	JUMP,EQ	80$	DEC.W	(A6)+ONOSEL	CALL	AFINFO		; montre la case slectionne	CLR.W	D7		; D7 <-- ok	JUMP	90$35$:				; DESCEND =>	COMP.W	(A6)+ONOSEL,#MAXSEL-1	JUMP,HS	80$	INC.W	(A6)+ONOSEL	CALL	AFINFO		; montre la case slectionne	CLR.W	D7		; D7 <-- ok	JUMP	90$40$:				; RETURN =>	COMP.W	(A6)+ONOSEL,#MAXSEL-1	JUMP,LO	42$	LOAD.W	(A6)+ONOSEL,#-142$:	INC.W	(A6)+ONOSEL	CALL	AFINFO		; montre la case slectionne	CLR.W	D7		; D7 <-- ok	JUMP	90$50$:	LOAD.W	D5,(A6)+ONOSEL	; D5 <-- no de la case	CALL	DIMINUE	JUMP,NE	80$	CALL	ASKMAJ		; mj l'affichage	CLR.W	D7	JUMP	90$60$:	LOAD.W	D5,(A6)+ONOSEL	; D5 <-- no de la case	CALL	AUGMENTE	JUMP,NE	80$	CALL	ASKMAJ		; mj l'affichage	CLR.W	D7	JUMP	90$80$:	LOAD.B	D3,#BIPLIT	.W	LIB,?BEEP90$:	POPM.L	D3,D4,D5	TEST.W	D7		; retour EQ/NE	RET;--------\; ASKCMX  >;--------/; Attend un paramtre horizontal, en centimtres.; in	D5.W	no case;	D3.W	1re touche; out	D7.W	erreur; mod	D7.WASKCMX:	PUSHM.L	D3,D4,A3	CALL	ASKLNUM		; A3 <-- ^nombre en ASCII	JUMP,EQ	20$	CALL	AFINFO	LOAD.W	D7,#1	JUMP	90$20$:	LOAD.B	D3,#2		; D3 <-- 2 dcimales	CALL	ASKTNUM		; D4 <-- nombre en binaire	INC.W	D4		; corrige erreur d'arrondi !	MUL.WU	D4,#240/2	DIV.WU	D4,#254/2	CALL	PUTSEL		; mj le paramtre	CALL	ASKMAJ		; mj l'affichage	CLR.W	D790$:	POPM.L	D3,D4,A3	TEST.W	D7		; retour EQ/NE	RET;--------\; ASKCMY  >;--------/; Attend un paramtre vertical, en centimtres.; in	D5.W	no case;	D3.W	1re touche; out	D7.W	erreur; mod	D7.WASKCMY:	PUSHM.L	D3,D4,A3	CALL	ASKLNUM		; A3 <-- ^nombre en ASCII	JUMP,EQ	20$	CALL	AFINFO	LOAD.W	D7,#1	JUMP	90$20$:	LOAD.B	D3,#2		; D3 <-- 2 dcimales	CALL	ASKTNUM		; D4 <-- nombre en binaire	INC.W	D4		; corrige erreur d'arrondi !	MUL.WU	D4,#288/2	DIV.WU	D4,#254/2	CALL	PUTSEL		; mj le paramtre	CALL	ASKMAJ		; mj l'affichage	CLR.W	D790$:	POPM.L	D3,D4,A3	TEST.W	D7		; retour EQ/NE	RET;--------\; ASKMMX  >;--------/; Attend un paramtre horizontal, en millimtres.; in	D5.W	no case;	D3.W	1re touche; out	D7.W	erreur; mod	D7.WASKMMX:	PUSHM.L	D3,D4,A3	CALL	ASKLNUM		; A3 <-- ^nombre en ASCII	JUMP,EQ	20$	CALL	AFINFO	LOAD.W	D7,#1	JUMP	90$20$:	LOAD.B	D3,#1		; D3 <-- une dcimale	CALL	ASKTNUM		; D4 <-- nombre en binaire	INC.W	D4		; corrige erreur d'arrondi !	MUL.WU	D4,#240/2	DIV.WU	D4,#254/2	CALL	PUTSEL		; mj le paramtre	CALL	ASKMAJ		; mj l'affichage	CLR.W	D790$:	POPM.L	D3,D4,A3	TEST.W	D7		; retour EQ/NE	RET;--------\; ASKMMY  >;--------/; Attend un paramtre horizontal, en millimtres.; in	D5.W	no case;	D3.W	1re touche; out	D7.W	erreur; mod	D7.WASKMMY:	PUSHM.L	D3,D4,A3	CALL	ASKLNUM		; A3 <-- ^nombre en ASCII	JUMP,EQ	20$	CALL	AFINFO	LOAD.W	D7,#1	JUMP	90$20$:	LOAD.B	D3,#1		; D3 <-- une dcimale	CALL	ASKTNUM		; D4 <-- nombre en binaire	INC.W	D4		; corrige erreur d'arrondi !	MUL.WU	D4,#288/2	DIV.WU	D4,#254/2	CALL	PUTSEL		; mj le paramtre	CALL	ASKMAJ		; mj l'affichage	CLR.W	D790$:	POPM.L	D3,D4,A3	TEST.W	D7		; retour EQ/NE	RET;--------\; ASKNB   >;--------/; Attend un paramtre numrique sans unit.; in	D5.W	no case;	D3.W	1re touche; out	D7.W	erreur; mod	D7.WASKNB:	PUSHM.L	D3,D4,A3	CALL	ASKLNUM		; A3 <-- ^nombre en ASCII	JUMP,EQ	20$	CALL	AFINFO	LOAD.W	D7,#1	JUMP	90$20$:	CLR.B	D3		; D3 <-- aucune dcimale	CALL	ASKTNUM		; D4 <-- nombre en binaire	CALL	PUTSEL		; mj le paramtre	CALL	AFINFO		; affiche nombre correctement	CALL	AFPINT		; affiche surface dans page	CLR.W	D790$:	POPM.L	D3,D4,A3	TEST.W	D7		; retour EQ/NE	RET;--------\; ASKMAJ  >;--------/; Met  jour l'affichage aprs la modification d'un paramtre.; in	D5.W	numro de la case; out	-; mod	D7.WASKMAJ:	CALL	AFINFO		; affiche le nombre correctement	COMP.W	D5,#CASITL	JUMP,EQ	90$	COMP.W	D5,#CASITC	JUMP,EQ	90$	COMP.W	D5,#CASNBL	JUMP,EQ	90$	COMP.W	D5,#CASNBC	JUMP,EQ	90$	COMP.W	D5,#CASHTP	JUMP,EQ	40$	COMP.W	D5,#CASLGP	JUMP,EQ	40$	CALL	OPEPRINT	; init variables pour dessin	CALL	AFPINT		; affiche surface dans page	JUMP	90$40$:	CALL	INIPRINT	; init l'chelle	CALL	OPEPRINT	; init variables pour dessin	CALL	AFPEXT		; affiche la page	CALL	AFPINT		; affiche surface dans page90$:	RET;--------\; ASKLNUM >;--------/; Attend une ligne constitue de chiffres.; in	D3.B	1re touche presse;	D5.W	numro de la case; out	A3.L	^ligne;	D7.W	erreur; mod	D7.W, A3.LASKLNUM:	PUSHM.L	D2,D3,D4,A4	LOAD.L	A3,#R16"TXMENU	.W	LIB,?AFMENU	PUSH.W	D5	LOAD.W	D5,(A6)+ONOWDT	.W	LIB,?USEWDO	; utilise swdo texte	POP.W	D5	LOAD.L	A3,#(A6)+OBUNAM	LOAD.L	A4,A3	CLR.B	(A4)	CLR.W	D2		; D2 <-- lg ligne	JUMP	22$10$:	CALL	ASKLAFF		; affiche la ligne20$:	.W	LIB,?GETKEY	; attend clavier/souris ...	TEST.L	D3:#BKPSEUDO	; pseudo code/touche relache ?	JUMP,BS	20$		; oui => 20$22$:	LOAD.W	D7,#1	COMP.B	D3,#END	JUMP,EQ	90$	COMP.B	D3,#F0	JUMP,EQ	90$	COMP.B	D3,#F0+SHIFT	JUMP,EQ	90$	COMP.B	D3,#UNDO	JUMP,EQ	90$	COMP.W	D3,#KEYMPO	JUMP,EQ	20$	COMP.W	D3,#KEYMGP	JUMP,EQ	90$	COMP.W	D3,#KEYMMP	JUMP,EQ	90$	COMP.W	D3,#KEYMDP	JUMP,EQ	90$	COMP.W	D3,#KEYMGR	JUMP,EQ	90$	COMP.W	D3,#KEYMMR	JUMP,EQ	90$	COMP.W	D3,#KEYMDR	JUMP,EQ	90$	COMP.B	D3,#CR	JUMP,EQ	70$	COMP.B	D3,#ENTER	JUMP,EQ	70$	COMP.B	D3,#CLEAR	JUMP,EQ	60$	COMP.B	D3,#DELETE	JUMP,EQ	50$	COMP.B	D3,#DEL	JUMP,EQ	50$	COMP.B	D3,#BS	JUMP,EQ	50$	COMP.B	D3,#'.	JUMP,EQ	35$	COMP.B	D3,#',	JUMP,EQ	35$	COMP.B	D3,#POINT	JUMP,EQ	35$	COMP.B	D3,#'0	JUMP,LO	30$	COMP.B	D3,#'9	JUMP,LS	40$30$:	LOAD.B	D3,#BIPLIT	.W	LIB,?BEEP	; p'tit bruit	JUMP	20$35$:	LOAD.B	D3,#'.		; D3 <-- insre un point40$:				; insre un caractre	TEST.L	D3:#7	JUMP,BS	30$	COMP.W	D2,#LBUNAM-1	; buffer plein ?	JUMP,HS	30$		; oui => 30$	INC.W	D2	LOAD.B	(A4+),D3	CLR.B	(A4)	JUMP	10$50$:				; dtruit un caractre	TEST.W	D2		; buffer vide ?	JUMP,EQ	30$		; oui => 30$	DEC.W	D2	CLR.B	(A4)-1	JUMP	10$60$:				; dtruit tout	TEST.W	D2		; buffer dj vide ?	JUMP,EQ	30$		; oui => 30$	CLR.W	D2	CLR.B	(A3)	JUMP	10$70$:				; termine l'insertion	CLR.W	D7		; D7 <-- ok90$:	PUSHM.L	D5,D7,A3	LOAD.B	D3,#NOCURS	.W	LIB,?AFCAR	CLR.W	D5	.W	LIB,?USEWDO	; utilise swdo principale	LOAD.L	A3,#R16"TXMEN1	.W	LIB,?AFMENU	; remet le bon menu	POPM.L	D5,D7,A3	POPM.L	D2,D3,D4,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; ASKLAFF >;--------/; Affiche une ligne en cours de frappe.; in	A3.L	^dbut de la ligne; out	A4.L	^sur le zro terminateur; mod	D7.W, A4.LASKLAFF:	PUSHM.L	D3,D4	.W	LIB,?BUCAR	; mode rapide	.W	LIB,?AFTIM	.B	NOCURS		; plus de curseur provisoirement	.B	0	.EVEN	LOAD.L	A4,#(A6)+OPOINF	; A4 <-- ^buffer des positions	LOAD.W	D4,D5		; D4 <-- numro de la case	MUL.WU	D4,#4	LOAD.L	D3,(A4)+(D4.W)	.W	LIB,?SETCURS	; positionne au dbut de la ligne	LOAD.L	A4,A3		; A4 <-- ^dbut ligne	LOAD.W	D4,#-1		; D4 <-- nb caractre jusqu' la virgule10$:	INC.W	D4	TEST.B	(A4+)	JUMP,EQ	15$	COMP.B	(A4)-1,#'.	JUMP,NE	10$15$:	SUB.W	D4,#3	NEG.W	D4	JUMP,LE	20$	LOAD.B	D3,#MSPACE	.W	LIB,?AFCAR	; met qq blancs pour tabuler la virgule	LOAD.B	D3,D4	.W	LIB,?AFCAR20$:	LOAD.L	A4,A3		; A4 <-- ^dbut ligne30$:	LOAD.B	D3,(A4+)	JUMP,EQ	40$	.W	LIB,?AFCODE	; affiche toute la ligne	JUMP	30$40$:	DEC.L	A4		; A4 <-- ^sur le zro terminateur	.W	LIB,?AFTIM	.B	EFLI		; efface la fin de la ligne	.B	CURS		; remet le curseur	.B	0	.EVEN	.W	LIB,?NOBUCAR	; remet le mode normal	POPM.L	D3,D4	RET;--------\; ASKTNUM >;--------/; Transforme un nombre dcimal sous forme d'une chane ASCII en un; nombre binaire.; in	A3.L	^ligne;	D3.B	nb dcimales (0..n); out	D4.W	nombre; mod	D4.WASKTNUM:	PUSHM.L	D2,D3,A3	CLR.W	D4		; D4 <-- nombre	CLR.W	D2		; D2 <-- virgule pas rencontre	LOAD.B	D2,D3		; D2 <-- nb dcimale(s)10$:	LOAD.B	D3,(A3+)	JUMP,EQ	70$	COMP.B	D3,#'.		; virgule ?	JUMP,EQ	50$		; oui => 50$	COMP.B	D3,#'0	JUMP,LO	70$	COMP.B	D3,#'9	JUMP,HI	70$	SUB.B	D3,#'0		; D3 <-- 0..9	AND.W	D3,#H'FF	TEST.L	D2:#10		; virgule rencontre ?	JUMP,BC	20$		; non => 20$	TEST.B	D2		; attend encore une dcimale ?	JUMP,EQ	70$		; non => 70$	DEC.B	D220$:	MUL.WU	D4,#10	ADD.W	D4,D3	JUMP	10$50$:	TSET.L	D2:#10	JUMP	10$70$:	TEST.B	D2		; attend encore une dcimale ?	JUMP,EQ	90$		; non => 90$	DEC.B	D2	MUL.WU	D4,#10	JUMP	70$90$:	POPM.L	D2,D3,A3	RET;--------\; ASKCAR  >;--------/; Attend paramtre.; in	D5.W	no case;	D3.W	1re touche; out	D7.W	erreur; mod	D7.WASKCAR:	PUSHM.L	D3,D4	PUSH.W	D5	LOAD.W	D5,(A6)+ONOWDT	.W	LIB,?USEWDO	; utilise swdo texte	POP.W	D5	.W	LIB,?MINMAJ	LOAD.W	D7,#1	COMP.B	D3,#'A	JUMP,LO	90$	COMP.B	D3,#'Z	JUMP,HI	90$	LOAD.B	D4,D3	CALL	PUTSEL	CALL	AFSEL	CLR.W	D790$:	PUSHM.W	D5,D7	CLR.W	D5	.W	LIB,?USEWDO	; utilise swdo principale	POPM.W	D5,D7	POPM.L	D3,D4	RET;--------\; DETECTE >;========/; Dtecte o est la souris.; in	D4.L	position de la souris; out	D0.B	bits des lignes;	D7.W	erreur; mod	D0.W, D7.WDETECTE:	PUSHM.L	D1,D2,D3,D4,A4	LOAD.W	D7,#1		; D7 <-- aucune dtection	LOAD.W	D3,D4		; D3 <-- X	SWAP.W	D4		; D4 <-- Y	LOAD.L	A4,#(A6)+OPOINF	; A4 <-- ^positions des cases	COMP.W	D3,(A4)+2	; avant dbut case en X ?	JUMP,LO	15$		; oui => 15$	LOAD.W	D1,(A6)+OBUSTD+ODFCX	MUL.WU	D1,#10	ADD.W	D1,(A4)+2	COMP.W	D3,D1		; aprs fin case en X ?	JUMP,HS	15$		; oui => 15$	LOAD.W	D2,#MAXSEL05$:	LOAD.W	D1,(A4)+0	SUB.W	D1,(A6)+OBUSTD+ODFC1Y	COMP.W	D4,D1		; plus haut ?	JUMP,LO	10$		; oui => 10$	LOAD.W	D1,(A4)+0	ADD.W	D1,(A6)+OBUSTD+ODFC2Y	COMP.W	D4,D1		; plus bas ?	JUMP,HI	10$		; oui => 10$				; non =>	SUB.W	D2,#MAXSEL	NEG.W	D2	LOAD.W	(A6)+ONOSEL,D2	; slectionne nouvelle case	LOAD.B	D0,#-1	CLR.W	D7	JUMP	90$10$:	ADD.L	A4,#4		; A4 <-- ^position suivante	DEC.W	D2	JUMP,NE	05$15$:	SUB.W	D3,(A6)+OWDOGX	JUMP,LO	90$	SUB.W	D4,(A6)+OWDOGY	JUMP,LO	90$	LOAD.W	(A6)+OMOUOR+2,D3	LOAD.W	(A6)+OMOUOR+0,D4	LOAD.L	(A6)+OINTOR,(A6)+OOINT	CLR.B	D0		; D0 <-- lignes dtectes	COMP.W	D4,(A6)+OOEXTY	JUMP,LO	90$	LOAD.W	D1,(A6)+OOINTY	ADD.W	D1,#LDETECTE	; sur la ligne suprieure ?	COMP.W	D4,D1	JUMP,HS	20$	TSET.L	D0:#BOPSUP20$:	LOAD.W	D1,(A6)+OOINTY	ADD.W	D1,(A6)+OLINTY	SUB.W	D1,#LDETECTE	COMP.W	D4,D1	JUMP,LO	30$	LOAD.W	D1,(A6)+OOEXTY	ADD.W	D1,(A6)+OLEXTY	; sur la ligne infrieure ?	COMP.W	D4,D1	JUMP,HS	90$	TSET.L	D0:#BOPINF30$:	COMP.W	D3,(A6)+OOEXTX	JUMP,LO	90$	LOAD.W	D1,(A6)+OOINTX	ADD.W	D1,#LDETECTE	; sur la ligne gauche ?	COMP.W	D3,D1	JUMP,HS	40$	TSET.L	D0:#BOPGAU40$:	LOAD.W	D1,(A6)+OOINTX	ADD.W	D1,(A6)+OLINTX	SUB.W	D1,#LDETECTE	COMP.W	D3,D1	JUMP,LO	50$	LOAD.W	D1,(A6)+OOEXTX	ADD.W	D1,(A6)+OLEXTX	; sur la ligne droite ?	COMP.W	D3,D1	JUMP,HS	90$	TSET.L	D0:#BOPDRO50$:	CLR.W	D7		; D7 <-- qq chose trouv90$:	POPM.L	D1,D2,D3,D4,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; MODIF   >;========/; Modifie le rectangle intrieur en fonction d'un dplacement; de la souris.; in	D4.L	position de la souris;	D0.B	bits des lignes trouves; out	D7.W	erreur; mod	D7.WMODIF:	PUSHM.L	D1,D3,D4	LOAD.W	D7,#1		; D7 <-- aucune dtection	LOAD.W	D3,D4		; D3 <-- X	SWAP.W	D4		; D4 <-- Y	SUB.W	D3,(A6)+OWDOGX	JUMP,LO	90$	SUB.W	D4,(A6)+OWDOGY	JUMP,LO	90$	TEST.B	D0		; au centre ?	JUMP,EQ	60$		; oui => 60$	TEST.L	D0:#BOPSUP	JUMP,BC	20$	LOAD.W	D1,(A6)+OOINTY	LOAD.W	(A6)+OOINTY,D4	SUB.W	D1,D4	ADD.W	(A6)+OLINTY,D120$:	TEST.L	D0:#BOPINF	JUMP,BC	30$	LOAD.W	D1,D4	SUB.W	D1,(A6)+OOINTY	LOAD.W	(A6)+OLINTY,D130$:	TEST.L	D0:#BOPGAU	JUMP,BC	40$	LOAD.W	D1,(A6)+OOINTX	LOAD.W	(A6)+OOINTX,D3	SUB.W	D1,D3	ADD.W	(A6)+OLINTX,D140$:	TEST.L	D0:#BOPDRO	JUMP,BC	50$	LOAD.W	D1,D3	SUB.W	D1,(A6)+OOINTX	LOAD.W	(A6)+OLINTX,D150$:	JUMP	80$60$:	SUB.W	D3,(A6)+OMOUOR+2	LOAD.W	D1,(A6)+OINTOR+2	ADD.W	D1,D3	LOAD.W	(A6)+OOINTX,D1	SUB.W	D4,(A6)+OMOUOR+0	LOAD.W	D1,(A6)+OINTOR+0	ADD.W	D1,D4	LOAD.W	(A6)+OOINTY,D180$:	CALL	LIMITES		; vrifie si tout est ok90$:	POPM.L	D1,D3,D4	TEST.W	D7		; retour EQ/NE	RET;--------\; LIMITES >;========/; Vrifie (aprs une modification) si le rectangle intrieur; n'est pas trop grand, ou s'il dborde.; in	-; out	D7.W	erreur; mod	D7.WLIMITES:	PUSHM.L	D1,D2,D3,D4	CLR.W	D7		; D7 <-- ok	COMP.W	(A6)+OLINTX,#LGMINX ; trop petit en X ?	JUMP,GE	10$	LOAD.W	(A6)+OLINTX,#LGMINX	LOAD.W	D7,#110$:	COMP.W	(A6)+OLINTY,#LGMINY ; trop petit en Y ?	JUMP,GE	15$	LOAD.W	(A6)+OLINTY,#LGMINY	LOAD.W	D7,#115$:	LOAD.W	D1,(A6)+OOEXTX	; D1 <-- limite gauche	LOAD.W	D2,D1	ADD.W	D2,(A6)+OLEXTX	; D2 <-- limite droite	LOAD.W	D3,(A6)+OOINTX	; D3 <-- extrme gauche	LOAD.W	D4,D3	ADD.W	D4,(A6)+OLINTX	; D4 <-- extrme droite	COMP.W	D3,D1		; trop  gauche ?	JUMP,GE	20$	LOAD.W	D3,D1	LOAD.W	D7,#120$:	COMP.W	D4,D2		; trop  droite ?	JUMP,LE	25$	LOAD.W	D4,D2	LOAD.W	D7,#125$:	LOAD.W	(A6)+OOINTX,D3	; mj extrme gauche	SUB.W	D4,D3	LOAD.W	(A6)+OLINTX,D4	; mj largeur	LOAD.W	D1,(A6)+OOEXTY	; D1 <-- limite sup.	LOAD.W	D2,D1	ADD.W	D2,(A6)+OLEXTY	; D2 <-- limite inf.	LOAD.W	D3,(A6)+OOINTY	; D3 <-- extrme sup.	LOAD.W	D4,D3	ADD.W	D4,(A6)+OLINTY	; D4 <-- extrme inf.	COMP.W	D3,D1		; trop haut ?	JUMP,GE	40$	LOAD.W	D3,D1	LOAD.W	D7,#140$:	COMP.W	D4,D2		; trop bas ?	JUMP,LE	45$	LOAD.W	D4,D2	LOAD.W	D7,#145$:	LOAD.W	(A6)+OOINTY,D3	; mj extrme sup.	SUB.W	D4,D3	LOAD.W	(A6)+OLINTY,D4	; mj hauteur	POPM.L	D1,D2,D3,D4	TEST.W	D7		; retour EQ/NE	RET;--------\; CHECK   >;========/; Vrifie si le status de l'imprimante est plausible.; in	-; out	-; mod	-CHECK:	PUSHM.L	D3,D4	COMP.W	(A6)+OBUSTP+OPRHTP,#LGMINY ; page trop courte ?	JUMP,HS	10$	LOAD.W	(A6)+OBUSTP+OPRHTP,#LGMINY10$:	COMP.W	(A6)+OBUSTP+OPRLGP,#LGMINX ; page trop troite ?	JUMP,HS	15$	LOAD.W	(A6)+OBUSTP+OPRLGP,#LGMINX15$:	TEST.W	(A6)+OBUSTP+OPRMGS	JUMP,NC	20$	CLR.W	(A6)+OBUSTP+OPRMGS20$:	TEST.W	(A6)+OBUSTP+OPRMGI	JUMP,NC	21$	CLR.W	(A6)+OBUSTP+OPRMGI21$:	TEST.W	(A6)+OBUSTP+OPRMGG	JUMP,NC	22$	CLR.W	(A6)+OBUSTP+OPRMGG22$:	TEST.W	(A6)+OBUSTP+OPRMGD	JUMP,NC	23$	CLR.W	(A6)+OBUSTP+OPRMGD23$:	TEST.W	(A6)+OBUSTP+OPRITL	JUMP,NC	24$	CLR.W	(A6)+OBUSTP+OPRITL24$:	TEST.W	(A6)+OBUSTP+OPRITC	JUMP,NC	25$	CLR.W	(A6)+OBUSTP+OPRITC25$:	LOAD.W	D4,(A6)+OBUSTP+OPRHTP	LOAD.W	D3,(A6)+OBUSTP+OPRMGS	ADD.W	D3,(A6)+OBUSTP+OPRMGI	ADD.W	D3,#LGMINY	COMP.W	D4,D3			; marges sup/inf trop grandes ?	JUMP,HS	40$	CLR.W	(A6)+OBUSTP+OPRMGS	CLR.W	(A6)+OBUSTP+OPRMGI40$:	LOAD.W	D4,(A6)+OBUSTP+OPRLGP	LOAD.W	D3,(A6)+OBUSTP+OPRMGG	ADD.W	D3,(A6)+OBUSTP+OPRMGD	ADD.W	D3,#LGMINX	COMP.W	D4,D3			; marges gauche/droite trop grandes ?	JUMP,HS	45$	CLR.W	(A6)+OBUSTP+OPRMGG	CLR.W	(A6)+OBUSTP+OPRMGD45$:	LOAD.W	D4,(A6)+OBUSTP+OPRHTP	SUB.W	D4,(A6)+OBUSTP+OPRMGS	SUB.W	D4,(A6)+OBUSTP+OPRMGI	COMP.W	D4,(A6)+OBUSTP+OPRITL	; interligne trop grand ?	JUMP,HS	50$	LOAD.W	(A6)+OBUSTP+OPRITL,D450$:	LOAD.W	D4,(A6)+OBUSTP+OPRLGP	SUB.W	D4,(A6)+OBUSTP+OPRMGG	SUB.W	D4,(A6)+OBUSTP+OPRMGD	COMP.W	D4,(A6)+OBUSTP+OPRITC	; intercaractre trop grand ?	JUMP,HS	55$	LOAD.W	(A6)+OBUSTP+OPRITC,D455$:	TEST.W	(A6)+OBUSTP+OPRITL	; interligne trop petit ?	JUMP,NE	60$	INC.W	(A6)+OBUSTP+OPRITL60$:	TEST.W	(A6)+OBUSTP+OPRITC	; intercaractre trop petit ?	JUMP,NE	65$	INC.W	(A6)+OBUSTP+OPRITC65$:	POPM.L	D3,D4	RET;--------\; AFTINFO >;========/; Affiche les textes fixes pour qq renseignements.; in	-; out	-; mod	D7.WAFTINFO:	PUSHM.L	D3,D4,D5,A4	LOAD.W	D5,(A6)+ONOWDT	.W	LIB,?USEWDO	; utilise swdo texte	LOAD.L	A4,#(A6)+OPOINF	; A4 <-- ^buffer pour positions	LOAD.W	D3,(A6)+OBUSTD+ODFCY	MUL.WU	D3,#4		; laisse 4 lignes vides	SWAP.W	D3	CLR.W	D3	.W	LIB,?SETCURS	LOAD.W	D4,(A6)+OBUSTD+ODFCX	MUL.WU	D4,#25	.W	LIB,?AFTIM	.B	CR	.ASCIZ	"Hauteur du papier"	.EVEN	.W	LIB,?GETCURS	LOAD.W	D3,D4	LOAD.L	(A4+),D3	.W	LIB,?AFTIM	.B	CR	.ASCIZ	"Largeur du papier"	.EVEN	.W	LIB,?GETCURS	LOAD.W	D3,D4	LOAD.L	(A4+),D3	.W	LIB,?AFTIM	.B	CR,CR	.ASCIZ	"Marge gauche"	.EVEN	.W	LIB,?GETCURS	LOAD.W	D3,D4	LOAD.L	(A4+),D3	.W	LIB,?AFTIM	.B	CR	.ASCIZ	"Marge droite"	.EVEN	.W	LIB,?GETCURS	LOAD.W	D3,D4	LOAD.L	(A4+),D3	.W	LIB,?AFTIM	.B	CR	.ASCIZ	"Marge suprieure"	.EVEN	.W	LIB,?GETCURS	LOAD.W	D3,D4	LOAD.L	(A4+),D3	.W	LIB,?AFTIM	.B	CR	.ASCIZ	"Marge infrieure"	.EVEN	.W	LIB,?GETCURS	LOAD.W	D3,D4	LOAD.L	(A4+),D3	.W	LIB,?AFTIM	.B	CR,CR	.ASCIZ	"Interligne"	.EVEN	.W	LIB,?GETCURS	LOAD.W	D3,D4	LOAD.L	(A4+),D3	.W	LIB,?AFTIM	.B	CR	.ASCIZ	"Intercaractre"	.EVEN	.W	LIB,?GETCURS	LOAD.W	D3,D4	LOAD.L	(A4+),D3	.W	LIB,?AFTIM	.B	CR,CR	.ASCIZ	"Nb lignes par page"	.EVEN	.W	LIB,?GETCURS	LOAD.W	D3,D4	LOAD.L	(A4+),D3	.W	LIB,?AFTIM	.B	CR	.ASCIZ	"Nb caractres par ligne"	.EVEN	.W	LIB,?GETCURS	LOAD.W	D3,D4	LOAD.L	(A4+),D3	CLR.W	D5	.W	LIB,?USEWDO	; utilise swdo principale	POPM.L	D3,D4,D5,A4	RET;--------\; AFINFO  >;========/; Affiche qq renseignements (seulement les pramtres).; in	-; out	-; mod	D7.WAFINFO:	PUSHM.L	D3,D4,D5	LOAD.W	D5,(A6)+ONOWDT	.W	LIB,?USEWDO	; utilise swdo texte	.W	LIB,?BUCAR	; mode rapide	CLR.W	D510$:	CALL	GETSEL		; D4 <-- paramtre	CALL	AFSEL		; affiche le paramtre	INC.W	D5		; D5 <-- no case suivante	COMP.W	D5,#MAXSEL	JUMP,LO	10$	.W	LIB,?NOBUCAR	; remet mode normal	CLR.W	D5	.W	LIB,?USEWDO	; utilise swdo principale	POPM.L	D3,D4,D5	RET;--------\; AFCMX   >;--------/; Transforme puis affiche un nombre en centimtres.; in	D4.W	nombre;	D5.W	rang; out	-; mod	D4.L, D7.WAFCMX:	MUL.WU	D4,#254/2	DIV.WU	D4,#240/2	; 240me d'inch en X	JUMP	AFCM;--------\; AFCMY   >;--------/; Transforme puis affiche un nombre en centimtres.; in	D4.W	nombre;	D5.W	rang; out	-; mod	D4.L, D7.WAFCMY:	MUL.WU	D4,#254/2	DIV.WU	D4,#288/2	; 288me d'inch en X;	JUMP	AFCMAFCM:	PUSHM.L	D1,D2,D3	COMP.W	D5,(A6)+ONOSEL	; case slectionne ?	JUMP,NE	10$		; non => 10$	LOAD.B	D3,#AFINV	; oui =>	.W	LIB,?AFCAR	; passe en vido-inverse10$:	AND.L	D4,#H'FFFF	DIV.WU	D4,#100		; D4 <-- nombre en centimtres	LOAD.L	D1,D4	AND.L	D4,#H'FFFF	LOAD.B	D3,#3		; D3 <-- 3 digits	CLR.W	D2		; D2 <-- mode	.W	LIB,?AFDEC	; affiche partie entire	LOAD.B	D3,#'.	.W	LIB,?AFCAR	CLR.W	D1	SWAP.W	D1		; D1 <-- reste (fraction)	DIV.WU	D1,#10	ADD.B	D1,#'0	LOAD.B	D3,D1	.W	LIB,?AFCAR	; affiche partie fractionnaire	.W	LIB,?AFTIM	.ASCIZ	" cm <AFDIR><EFLI>"	.EVEN	POPM.L	D1,D2,D3	RET;--------\; AFMMX   >;--------/; Transforme puis affiche un nombre en millimtres.; in	D4.W	nombre;	D5.W	rang; out	-; mod	D4.L, D7.WAFMMX:	MUL.WU	D4,#254/2	DIV.WU	D4,#240/2	; 240me d'inch en X	JUMP	AFMM;--------\; AFMMY   >;--------/; Transforme puis affiche un nombre en millimtres.; in	D4.W	nombre;	D5.W	rang; out	-; mod	D4.L, D7.WAFMMY:	MUL.WU	D4,#254/2	DIV.WU	D4,#288/2	; 288me d'inch en X;	JUMP	AFMMAFMM:	PUSHM.L	D1,D2,D3	COMP.W	D5,(A6)+ONOSEL	; case slectionne ?	JUMP,NE	10$		; non => 10$	LOAD.B	D3,#AFINV	; oui =>	.W	LIB,?AFCAR	; passe en vido-inverse10$:	AND.L	D4,#H'FFFF	DIV.WU	D4,#10		; D4 <-- nombre en millimtres	LOAD.L	D1,D4	AND.L	D4,#H'FFFF	LOAD.B	D3,#3		; D3 <-- 3 digits	CLR.W	D2		; D2 <-- mode	.W	LIB,?AFDEC	; affiche partie entire	LOAD.B	D3,#'.	.W	LIB,?AFCAR	CLR.W	D1	SWAP.W	D1		; D1 <-- reste (fraction)	ADD.B	D1,#'0	LOAD.B	D3,D1	.W	LIB,?AFCAR	; affiche partie fractionnaire	.W	LIB,?AFTIM	.ASCIZ	" mm <AFDIR><EFLI>"	.EVEN	POPM.L	D1,D2,D3	RET;--------\; AFNB    >;--------/; Affiche un nombre sans unit.; in	D4.W	nombre;	D5.W	rang; out	-; mod	D4.L, D7.WAFNB:	PUSHM.L	D2,D3	COMP.W	D5,(A6)+ONOSEL	; case slectionne ?	JUMP,NE	10$		; non => 10$	LOAD.B	D3,#AFINV	; oui =>	.W	LIB,?AFCAR	; passe en vido-inverse10$:	AND.L	D4,#H'FFFF	LOAD.B	D3,#3		; D3 <-- 3 digits	CLR.W	D2		; D2 <-- mode	.W	LIB,?AFDEC	; affiche le nombre	.W	LIB,?AFTIM	.ASCIZ	" <AFDIR><EFLI>"	.EVEN	POPM.L	D2,D3	RET;--------\; AFFON   >;--------/; Affiche un caractre pour la fonte.; in	D4.B	caractre;	D5.W	rang; out	-; mod	D4.L, D7.WAFFON:	PUSHM.L	D3,A3	COMP.W	D5,(A6)+ONOSEL	; case slectionne ?	JUMP,NE	10$		; non => 10$	LOAD.B	D3,#AFINV	; oui =>	.W	LIB,?AFCAR	; passe en vido-inverse10$:	.W	LIB,?AFSPACE	LOAD.L	A3,#R16"TAFONTES	CALL	SRCCAR	.W	LIB,?AFTEXT	; affiche la fonte	.W	LIB,?AFTIM	.ASCIZ	" <AFDIR><EFLI>"	.EVEN	POPM.L	D3,A3	RET;--------\; AFSTY   >;--------/; Affiche un caractre pour le style.; in	D4.B	caractre;	D5.W	rang; out	-; mod	D4.L, D7.WAFSTY:	PUSHM.L	D3,A3	COMP.W	D5,(A6)+ONOSEL	; case slectionne ?	JUMP,NE	10$		; non => 10$	LOAD.B	D3,#AFINV	; oui =>	.W	LIB,?AFCAR	; passe en vido-inverse10$:	.W	LIB,?AFSPACE	LOAD.L	A3,#R16"TASTYLES	CALL	SRCCAR	.W	LIB,?AFTEXT	; affiche le style	.W	LIB,?AFTIM	.ASCIZ	" <AFDIR><EFLI>"	.EVEN	POPM.L	D3,A3	RET;--------\; SRCCAR  >;--------/; Cherche un texte pour la fonte ou le style.; in	D4.B	caractre;	A3.L	^table; out	A3.L	^texte;	D7.W	erreur; mod	D7.W, A3.LSRCCAR:	PUSH.L	D3	LOAD.B	D3,D4	.W	LIB,?MINMAJ	; D3 <-- lettre MAJUSCULE	CLR.W	D7		; D7 <-- ok10$:	TEST.B	(A3)		; fin de la table ?	JUMP,EQ	50$	COMP.B	D3,(A3)	JUMP,EQ	90$20$:	TEST.B	(A3+)		; A3 <-- saute .ASCIZ	JUMP,NE	20$	JUMP	10$50$:	LOAD.L	A3,#(A6)+OBUNAM	LOAD.B	(A3)+0,D3	; met juste la lettre	CLR.B	(A3)+1	LOAD.W	D7,#1		; D7 <-- pas trouv90$:	POP.L	D3	TEST.W	D7		; retour EQ/NE	RET;--------\; NXTCAR  >;--------/; Cherche le texte suivant.; in	A3.L	^dbut table concerne;	D4.B	caractre; out	D4.B	caractre suivant; mod	D4.W, D7.WNXTCAR:	PUSHM.L	A3,A4	LOAD.L	A4,A3		; A4 <-- ^dbut table	CALL	SRCCAR		; A3 <-- ^texte actuel	JUMP,NE	50$20$:	TEST.B	(A3+)		; A3 <-- ^texte suivant	JUMP,NE	20$	TEST.B	(A3)		; dernier texte ?	JUMP,NE	80$		; non => 80$	LOAD.L	A3,A4		; oui => prend le premier	JUMP	80$50$:	INC.B	D4	COMP.B	D4,#'Z	JUMP,LS	90$	LOAD.B	D4,#'A	JUMP	90$80$:	LOAD.B	D4,(A3)		; D4 <-- caractre suivant90$:	POPM.L	A3,A4	RET;--------\; PRVCAR  >;--------/; Cherche le texte prcdent.; in	A3.L	^dbut table concerne;	D4.B	caractre; out	D4.B	caractre prcdent; mod	D4.W, D7.WPRVCAR:	PUSHM.L	A3,A4	LOAD.L	A4,A3		; A4 <-- ^dbut table	CALL	SRCCAR		; A3 <-- ^texte actuel	JUMP,NE	50$20$:	COMP.L	A3,A4		; premier texte ?	JUMP,EQ	40$		; oui => 40$	DEC.L	A330$:	TEST.B	(-A3)		; A3 <-- ^texte prcdent	JUMP,NE	30$	INC.L	A3	JUMP	80$40$:	TEST.B	(A3+)	JUMP,NE	40$	TEST.B	(A3)	JUMP,NE	40$	JUMP	20$50$:	DEC.B	D4	COMP.B	D4,#'A	JUMP,HS	90$	LOAD.B	D4,#'Z	JUMP	90$80$:	LOAD.B	D4,(A3)		; D4 <-- caractre prcdent90$:	POPM.L	A3,A4	RET;--------\; AFPEXT  >;========/; Affiche les dimensions extrieures de la page.; in	-; out	-; mod	D7.WAFPEXT:	PUSHM.L	D1,D2,D3,D4,D5	LOAD.W	D5,(A6)+ONOWDG	.W	LIB,?USEWDO	; utilise swdo graphique	LOAD.B	D3,#EOP	.W	LIB,?AFCAR	; efface toute la swdo	CLR.L	(A6)+OOLINT	; n'efface pas l'ancien rectangle	LOAD.W	D2,#SETDOT	; D2 <-- mode	LOAD.L	D3,(A6)+OOEXT	; D3 <-- origine (Y;X) page	LOAD.L	D4,(A6)+OLEXT	; D4 <-- dimensions (Y;X) page	LOAD.B	D1,#2		; D1 <-- double paisseur10$:	DEC.W	D3	SWAP.W	D3	DEC.W	D3	SWAP.W	D3	ADD.W	D4,#2	SWAP.W	D4	ADD.W	D4,#2	SWAP.W	D4	.W	LIB,?DRRECT	; dessine grand rectangle	DEC.B	D1	JUMP,NE	10$	LOAD.L	D3,#-1	LOAD.L	D4,#-1	.W	LIB,?DRMDEF	; dfini une trame pleine	LOAD.W	D3,(A6)+OOEXTY	ADD.W	D3,#LOMBRE	SWAP.W	D3	LOAD.W	D3,(A6)+OOEXTX	ADD.W	D3,(A6)+OLEXTX	INC.W	D3	LOAD.W	D4,(A6)+OLEXTY	SWAP.W	D4	LOAD.W	D4,#LOMBRE	.W	LIB,?DRMATRIX	; dessine ombre  droite	LOAD.W	D3,(A6)+OOEXTY	ADD.W	D3,(A6)+OLEXTY	INC.W	D3	SWAP.W	D3	LOAD.W	D3,(A6)+OOEXTX	ADD.W	D3,#LOMBRE	LOAD.W	D4,#LOMBRE	SWAP.W	D4	LOAD.W	D4,(A6)+OLEXTX	.W	LIB,?DRMATRIX	; dessine ombre en bas	CLR.W	D5	.W	LIB,?USEWDO	; utilise swdo principale	POPM.L	D1,D2,D3,D4,D5	RET;--------\; AFPINT  >;========/; Affiche les dimensions intrieures de la page.; in	-; out	-; mod	D7.WAFPINT:	PUSHM.L	D2,D3,D4,D5	LOAD.W	D5,(A6)+ONOWDG	.W	LIB,?USEWDO	; utilise swdo graphique	LOAD.L	D3,(A6)+OOOINT	; D3 <-- ancienne origine	LOAD.L	D4,(A6)+OOLINT	; D4 <-- ancienne dimension	LOAD.W	D2,#CLRDOT	.W	LIB,?DRRECT	; efface l'ancien rectangle	LOAD.L	D3,#H'88880000	; trame pour Smaky 8	LOAD.L	D4,#H'22220000	COMP.B	(A6)+OMACHINE,#2	JUMP,NE	10$	LOAD.L	D3,#H'88002200	; trame pour Smaky 100	LOAD.L	D4,#H'8800220010$:	.W	LIB,?DRMDEF	; dfini une trame grise	LOAD.W	D2,#SETDOT	; D2 <-- mode	LOAD.L	D3,(A6)+OOEXT	LOAD.W	D4,(A6)+OOINTY	SUB.W	D4,(A6)+OOEXTY	SWAP.W	D4	LOAD.W	D4,(A6)+OLEXTX	INC.W	D4	.W	LIB,?DRMATRIX	; dessine rectangle sup.	SWAP.W	D3	SWAP.W	D4	ADD.W	D3,D4	ADD.W	D3,(A6)+OLINTY	LOAD.W	D4,(A6)+OOEXTY	ADD.W	D4,(A6)+OLEXTY	SUB.W	D4,D3	INC.W	D4	SWAP.W	D4	SWAP.W	D3	.W	LIB,?DRMATRIX	; dessine rectangle inf.	LOAD.W	D3,(A6)+OOINTY	SWAP.W	D3	LOAD.W	D3,(A6)+OOEXTX	LOAD.W	D4,(A6)+OLINTY	SWAP.W	D4	LOAD.W	D4,(A6)+OOINTX	SUB.W	D4,(A6)+OOEXTX	.W	LIB,?DRMATRIX	; dessine rectangle gauche	ADD.W	D3,D4	ADD.W	D3,(A6)+OLINTX	LOAD.W	D4,(A6)+OOEXTX	ADD.W	D4,(A6)+OLEXTX	SUB.W	D4,D3	INC.W	D4	.W	LIB,?DRMATRIX	; dessine rectangle droite	CLR.L	D3	CLR.L	D4	.W	LIB,?DRMDEF	; dfini une trame vide	LOAD.L	D3,(A6)+OOINT	; D3 <-- origine (Y;X) page	LOAD.L	D4,(A6)+OLINT	; D4 <-- dimensions (Y;X) page	LOAD.W	D2,#CLRDOT	; D2 <-- mode	.W	LIB,?DRMATRIX	; efface rectangle	LOAD.W	D2,#SETDOT	; D2 <-- mode	.W	LIB,?DRRECT	; dessine pourtour rectangle	LOAD.L	(A6)+OOOINT,(A6)+OOINT	LOAD.L	(A6)+OOLINT,(A6)+OLINT	CLR.W	D5	.W	LIB,?USEWDO	; utilise swdo principale	POPM.L	D2,D3,D4,D5	RET;--------\; AFQINT  >;========/; Affiche les dimensions intrieures de la page en mode "quick".; in	-; out	-; mod	D7.WAFQINT:	PUSHM.L	D2,D3,D4,D5	LOAD.W	D5,(A6)+ONOWDG	.W	LIB,?USEWDO	; utilise swdo graphique	LOAD.W	D2,#INVDOT	LOAD.L	D3,(A6)+OOINT	; D3 <-- nouvelle origine	LOAD.L	D4,(A6)+OLINT	; D4 <-- nouvelle dimension	.W	LIB,?DRRECT	; dessine le nouveau rectangle	LOAD.L	D3,(A6)+OOOINT	; D3 <-- ancienne origine	LOAD.L	D4,(A6)+OOLINT	; D4 <-- ancienne dimension	.W	LIB,?DRRECT	; efface l'ancien rectangle	LOAD.L	(A6)+OOOINT,(A6)+OOINT	LOAD.L	(A6)+OOLINT,(A6)+OLINT	CLR.W	D5	.W	LIB,?USEWDO	; utilise swdo principale	POPM.L	D2,D3,D4,D5	RET;---------\; INIPRINT >;=========/; Initialise les paramtres pour l'affichage en fonction; du status de l'imprimante.; in	-; out	D7.W	erreur; mod	D7.WINIPRINT:	PUSHM.L	D2,D3,D4,D6,A3,A4	LOAD.W	D5,(A6)+ONOWDG	.W	LIB,?USEWDO	; utilise swdo graphique	JUMP,NE	90$	LOAD.L	A4,#(A6)+OBUSTD	; A4 <-- ^buffer	LOAD.L	D4,#LGDIS3	LOAD.W	D3,#TYPWDO	; D3 <-- type fentre	.W	LIB,?GCHDIS	; D6 <-- canal fentre	.W	FOS,?RSTATUS	; lit le status de la sous-fentre	JUMP,NE	90$	CLR.L	D3	LOAD.W	D3,(A6)+OBUSTP+OPRLGP	MUL.WU	D3,#FACORX	LOAD.W	D2,(A6)+OBUSTD+ODFFDX	SUB.W	D2,(A6)+OBUSTD+ODFCX	SUB.W	D2,(A6)+OBUSTD+ODFCX	SUB.W	D2,(A6)+OBUSTD+ODFCX	SUB.W	D2,(A6)+OBUSTD+ODFCX	DIV.WU	D3,D2	INC.W	D3		; D3 <-- facteur zoom en X	CLR.L	D4	LOAD.W	D4,(A6)+OBUSTP+OPRHTP	MUL.WU	D4,#FACORY	LOAD.W	D2,(A6)+OBUSTD+ODFFDY	SUB.W	D2,(A6)+OBUSTD+ODFCY	SUB.W	D2,(A6)+OBUSTD+ODFCY	SUB.W	D2,(A6)+OBUSTD+ODFCY	SUB.W	D2,(A6)+OBUSTD+ODFCY	DIV.WU	D4,D2	INC.W	D4		; D4 <-- facteur zoom en Y	COMP.W	D3,D4	JUMP,HS	20$	LOAD.W	D3,D4		; D3 <-- le plus grand facteur20$:	LOAD.W	(A6)+OFACT,D3	CLR.W	D5	.W	LIB,?USEWDO	CLR.W	D7		; D7 <-- ok90$:	POPM.L	D2,D3,D4,D6,A3,A4	TEST.W	D7		; retour EQ/NE	RET;---------\; OPEPRINT >;=========/; Initialise les variables pour le dessin de la page en; fonction du status de l'imprimante.; in	-; out	-; mod	-OPEPRINT:	PUSHM.L	D3,D4	CLR.L	D4	LOAD.W	D4,(A6)+OBUSTP+OPRLGP	MUL.WU	D4,#FACORX	DIV.WU	D4,(A6)+OFACT	LOAD.W	(A6)+OLEXTX,D4	SUB.W	D4,(A6)+OBUSTD+ODFFDX	NEG.W	D4	SUB.W	D4,(A6)+OBUSTD+ODFCX	SUB.W	D4,(A6)+OBUSTD+ODFCX	SUB.W	D4,(A6)+OBUSTD+ODFCX	SUB.W	D4,(A6)+OBUSTD+ODFCX	SR.W	D4,#1	ADD.W	D4,(A6)+OBUSTD+ODFCX	ADD.W	D4,(A6)+OBUSTD+ODFCX	LOAD.W	(A6)+OOEXTX,D4	CLR.L	D4	LOAD.W	D4,(A6)+OBUSTP+OPRHTP	MUL.WU	D4,#FACORY	DIV.WU	D4,(A6)+OFACT	LOAD.W	(A6)+OLEXTY,D4	SUB.W	D4,(A6)+OBUSTD+ODFFDY	NEG.W	D4	SUB.W	D4,(A6)+OBUSTD+ODFCY	SUB.W	D4,(A6)+OBUSTD+ODFCY	SUB.W	D4,(A6)+OBUSTD+ODFCY	SUB.W	D4,(A6)+OBUSTD+ODFCY	SR.W	D4,#1	ADD.W	D4,(A6)+OBUSTD+ODFCY	ADD.W	D4,(A6)+OBUSTD+ODFCY	LOAD.W	(A6)+OOEXTY,D4	CLR.L	D4	LOAD.W	D4,(A6)+OBUSTP+OPRMGG	MUL.WU	D4,#FACORX	DIV.WU	D4,(A6)+OFACT	ADD.W	D4,(A6)+OOEXTX	LOAD.W	(A6)+OOINTX,D4	CLR.L	D4	LOAD.W	D4,(A6)+OBUSTP+OPRMGS	MUL.WU	D4,#FACORY	DIV.WU	D4,(A6)+OFACT	ADD.W	D4,(A6)+OOEXTY	LOAD.W	(A6)+OOINTY,D4	CLR.L	D4	LOAD.W	D4,(A6)+OBUSTP+OPRLGP	SUB.W	D4,(A6)+OBUSTP+OPRMGG	SUB.W	D4,(A6)+OBUSTP+OPRMGD	MUL.WU	D4,#FACORX	DIV.WU	D4,(A6)+OFACT	LOAD.W	(A6)+OLINTX,D4	CLR.L	D4	LOAD.W	D4,(A6)+OBUSTP+OPRHTP	SUB.W	D4,(A6)+OBUSTP+OPRMGS	SUB.W	D4,(A6)+OBUSTP+OPRMGI	MUL.WU	D4,#FACORY	DIV.WU	D4,(A6)+OFACT	LOAD.W	(A6)+OLINTY,D4	POPM.L	D3,D4	RET;---------\; CLOPRINT >;=========/; Initialise le status de l'imprimante en fonction des; modifications effectues.; in	-; out	-; mod	-CLOPRINT:	PUSHM.L	D3,D4	LOAD.W	D4,(A6)+OOINTX	SUB.W	D4,(A6)+OOEXTX	LOAD.W	D3,D4	MUL.WU	D4,(A6)+OFACT	DIV.WU	D4,#FACORX	LOAD.W	(A6)+OBUSTP+OPRMGG,D4	LOAD.W	D4,(A6)+OLEXTX	SUB.W	D4,D3	SUB.W	D4,(A6)+OLINTX	MUL.WU	D4,(A6)+OFACT	DIV.WU	D4,#FACORX	LOAD.W	(A6)+OBUSTP+OPRMGD,D4	LOAD.W	D4,(A6)+OOINTY	SUB.W	D4,(A6)+OOEXTY	LOAD.W	D3,D4	MUL.WU	D4,(A6)+OFACT	DIV.WU	D4,#FACORY	LOAD.W	(A6)+OBUSTP+OPRMGS,D4	LOAD.W	D4,(A6)+OLEXTY	SUB.W	D4,D3	SUB.W	D4,(A6)+OLINTY	MUL.WU	D4,(A6)+OFACT	DIV.WU	D4,#FACORX	LOAD.W	(A6)+OBUSTP+OPRMGI,D4	POPM.L	D3,D4	RET;--------\; INIDIS  >;========/; Cre les sous-fentres.; in	-; out	D7.W	erreur; mod	D7.WINIDIS:	PUSHM.L	D0,D1,D2,D3,D4,D5,D6,A3,A4	LOAD.L	A4,#(A6)+OBUSTD	; A4 <-- ^buffer	LOAD.L	D4,#LGDIS3	LOAD.W	D3,#TYPWDO	; D3 <-- type fentre	.W	LIB,?GCHDIS	; D6 <-- canal fentre	.W	FOS,?RSTATUS	; lit le status de la fentre	JUMP,NE	90$	CLR.L	D3	LOAD.W	D4,(A6)+OBUSTD+ODFDY	SWAP.W	D4	LOAD.W	D4,(A6)+OBUSTD+ODFDX	SR.W	D4,#1	.W	LIB,?CREWDO	; cre swdo pour le texte	JUMP,NE	90$	LOAD.W	(A6)+ONOWDT,D5	ADD.W	D3,D4	SWAP.W	D3	SWAP.W	D4;;	ADD.W	D3,(A6)+OBUSTD+ODFCY;;	SUB.W	D4,(A6)+OBUSTD+ODFCY;;	SUB.W	D4,(A6)+OBUSTD+ODFCY	SWAP.W	D4	SWAP.W	D3	.W	LIB,?CREWDO	; cre swdo pour le graphique	JUMP,NE	90$	LOAD.W	(A6)+ONOWDG,D5	LOAD.L	(A6)+OWDOG,D3	; mm. origine swdo graphique90$:	POPM.L	D0,D1,D2,D3,D4,D5,D6,A3,A4	TEST.W	D7		; retour EQ/NE	RET;---------\; RSTPRINT >;=========/; Lit le status de l'imprimante.; in	-; out	D7.W	erreur; mod	D7.WRSTPRINT:	PUSHM.L	D3,D4,D6,A2,A3,A4	LOAD.L	A4,#R16"02$	TEST.B	(A6)+OFLAGS:#BDEBUG	JUMP,BS	10$	LOAD.L	A3,#R16"NAPRINT	; A3 <-- ^nom logique	CLR.W	D3		; D3 <-- lien pour tous	.W	FOS,?VASSIGN	; A4 <-- ^nom physique	JUMP,NE	90$	LOAD.W	D7,#ERUTYP	; D7 <-- type d'unit incorrect	COMP.B	D4,#TYPPRI	; type imprimante ?	JUMP,NE	90$		; non => 90$10$:	COMP.B	(A4+),#'$	; nom physique ?	JUMP,NE	90$		; non => 90$	LOAD.L	A2,#R16"00$	; A2 <-- ^pour Smaky 8	COMP.B	(A6)+OMACHINE,#2	JUMP,NE	15$	LOAD.L	A2,#R16"01$	; A2 <-- ^pour Smaky 10015$:	LOAD.L	A3,#(A6)+OBUNAM20$:	LOAD.B	(A3+),(A2+)	; OBUNAM <-- @:#MM0:SYS_	JUMP,NE	20$	DEC.L	A330$:	LOAD.B	(A3+),(A4+)	; OBUNAM <-- OKI84 (ou autre)	COMP.B	(A3)-1,#'_	JUMP,NE	30$	DEC.L	A340$:	LOAD.B	(A3+),(A2+)	; OBUNAM <-- .INFO	JUMP,NE	40$	LOAD.L	A3,#(A6)+OBUNAM	LOAD.W	D3,#2^BOPRD	; D3 <-- mode lecture	.W	FOS,?OPEN	; ouvre l'imprimante	JUMP,NE	90$	LOAD.L	A4,#(A6)+OBUSTP	; A4 <-- ^buffer	LOAD.L	D4,#LGPRI0	; D4 <-- lg demande	.W	FOS,?RDBYTE	; lit le status actuel	PUSH.W	D7	.W	FOS,?CLOSE	; ferme l'imprimante	POP.W	D790$:	POPM.L	D3,D4,D6,A2,A3,A4	TEST.W	D7		; retour EQ/NE	RET00$:	.ASCIZ	"@:#MM0:SYS_"	; prfixe	.ASCIZ	".INFO"		; postfixe01$:	.ASCIZ	"@:#MM0:100_"	; prfixe	.ASCIZ	".INFO"		; postfixe02$:	.ASCIZ	"$CP80_0"	.EVEN;---------\; WSTPRINT >;=========/; Ecrit le status  l'imprimante.; in	-; out	D7.W	erreur; mod	D7.WWSTPRINT:	PUSHM.L	D4,A4	LOAD.L	A4,#(A6)+OBUCOM	; A4 <-- ^buffer pour commande	LOAD.B	(A4+),#'H	LOAD.W	D4,(A6)+OBUSTP+OPRHTP	CALL	PUTCNUM	LOAD.B	(A4+),#'^	LOAD.W	D4,(A6)+OBUSTP+OPRMGS	CALL	PUTCNUM	LOAD.B	(A4+),#'V	LOAD.W	D4,(A6)+OBUSTP+OPRMGI	CALL	PUTCNUM	LOAD.B	(A4+),#'I	LOAD.W	D4,(A6)+OBUSTP+OPRITL	CALL	PUTCNUM	LOAD.B	(A4+),#'L	LOAD.W	D4,(A6)+OBUSTP+OPRLGP	CALL	PUTCNUM	LOAD.B	(A4+),#'<	LOAD.W	D4,(A6)+OBUSTP+OPRMGG	CALL	PUTCNUM	LOAD.B	(A4+),#'>	LOAD.W	D4,(A6)+OBUSTP+OPRMGD	CALL	PUTCNUM	LOAD.B	(A4+),#'J	LOAD.W	D4,(A6)+OBUSTP+OPRITC	CALL	PUTCNUM	CLR.B	(A4)-1		; termine la commande	LOAD.L	A4,#(A6)+OBUCOM	; A4 <-- ^commandes	CALL	SENDCOMM	; envoie les commandes90$:	POPM.L	D4,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; PUTCNUM >;--------/; Met une variable numrique en points dans le buffer; de commandes sous la forme :;	=nnnnn.nP,; in	D4.W	nombre;	A4.L	^dans buffer; out	A4.L	^plus loin; mod	A4.LPUTCNUM:	PUSHM.L	D3,D4	LOAD.B	(A4+),#'=	AND.L	D4,#H'FFFF	.W	LIB,?BINBCD	; D4 <-- nombre en BCD	LOAD.B	D2,#8-2		; D2 <-- nb max de digits	SL.L	D4,#4*210$:	LOAD.L	D3,D4	SWAP.W	D3	SR.W	D3,#8	SR.B	D3,#4	ADD.B	D3,#'0	LOAD.B	(A4+),D3	COMP.B	D2,#2	JUMP,NE	20$	LOAD.B	(A4+),#'.	; met la virgule20$:	SL.L	D4,#4		; D4 <-- pousse d'un digit	DEC.B	D2	JUMP,NE	10$	LOAD.B	(A4+),#'P	LOAD.B	(A4+),#',	POPM.L	D3,D4	RET;---------\\; SENDCOMM >;=========/; Envoie une commande  l'imprimante.; in	A4.L	^commande; out	D7.W	erreur; mod	D7.WSENDCOMM:	PUSHM.L	D3,D6,A3	LOAD.L	A3,#R16"NAPRINT	LOAD.W	D3,#2^BOPWR!2^BOPEXCL	.W	FOS,?OPEN	; ouvre l'imprimante	JUMP,NE	90$	LOAD.W	D3,#TYPPRI	; D3 <-- type	.W	FOS,?COMMAND	; envoie toutes les commandes	PUSH.W	D7	.W	FOS,?CLOSE	; ferme l'imprimante	POP.W	D790$:	POPM.L	D3,D6,A3	TEST.W	D7		; retour EQ/NE	RET;--------\; AFSEL   >;========/; Affiche une case quelconque.; in	D5.W	numro de la case;	D4.W	paramtre; out	-; mod	D7.WAFSEL:	PUSHM.L	D0,D3,D4,A0,A4	LOAD.L	A4,#(A6)+OPOINF	; A4 <-- ^buffer des positions	LOAD.W	D3,D5	MUL.WU	D3,#4	LOAD.L	D3,(A4)+(D3.W)	; D3 <-- position	.W	LIB,?SETCURS	LOAD.L	A4,#R16"TAINFO	LOAD.W	D3,D5	MUL.WU	D3,#10	CLR.L	D0	LOAD.W	D0,(A4)+(D3.W)+2	LOAD.L	A0,#R16"START	ADD.L	A0,D0	CALL	(A0)		; CALL AF...	POPM.L	D0,D3,D4,A0,A4	RET;--------\; ASKSEL  >;========/; Modifie une case quelconque.; in	D5.W	numro de la case;	D3.W	1re touche; out	-; mod	D7.WASKSEL:	PUSHM.L	D0,D3,D4,A0,A4	LOAD.L	A4,#R16"TAINFO	LOAD.W	D4,D5	MUL.WU	D4,#10	CLR.L	D0	LOAD.W	D0,(A4)+(D4.W)+4	LOAD.L	A0,#R16"START	ADD.L	A0,D0	CALL	(A0)		; CALL ASK...	POPM.L	D0,D3,D4,A0,A4	RET;---------\; AUGMENTE >;=========/; Augmente un paramtre.; in	D5.W	no case; out	D7.W	erreur; mod	D7.WAUGMENTE:	PUSHM.L	D3,D4,A3,A4	CALL	GETSEL		; D4 <-- paramtre	LOAD.L	A4,#R16"TAINFO	LOAD.W	D3,D5	MUL.WU	D3,#10	LOAD.W	D3,(A4)+(D3.W)+0	JUMP,EQ	80$	ADD.W	D4,D3		; augmente	CALL	PUTSEL		; mj paramtre	CLR.W	D7	JUMP	90$80$:	LOAD.B	D3,#BIPLIT	.W	LIB,?BEEP	; p'tit bruit	LOAD.W	D7,#190$:	POPM.L	D3,D4,A3,A4	TEST.W	D7		; retour EQ/NE	RET;---------\; DIMINUE  >;=========/; Diminue un paramtre.; in	D5.W	no case; out	D7.W	erreur; mod	D7.WDIMINUE:	PUSHM.L	D3,D4,A3,A4	CALL	GETSEL		; D4 <-- paramtre	LOAD.L	A4,#R16"TAINFO	LOAD.W	D3,D5	MUL.WU	D3,#10	LOAD.W	D3,(A4)+(D3.W)+0	JUMP,EQ	80$	SUB.W	D4,D3		; diminue	CALL	PUTSEL		; mj paramtre	CLR.W	D7	JUMP	90$80$:	LOAD.B	D3,#BIPLIT	.W	LIB,?BEEP	; p'tit bruit	LOAD.W	D7,#190$:	POPM.L	D3,D4,A3,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; GETSEL  >;========/; Donne le contenu d'une case quelconque.; in	D5.W	numro de la case; out	D4.W	paramtre; mod	D4.L, D7.WGETSEL:	PUSHM.L	D5,A4	LOAD.L	A4,#R16"TAINFO	MUL.WU	D5,#10	CLR.L	D4	LOAD.W	D4,(A4)+(D5.W)+6	LOAD.L	A4,#R16"START	ADD.L	A4,D4	CALL	(A4)		; CALL GET...	POPM.L	D5,A4	RET;--------\; PUTSEL  >;========/; Met  jour le contenu d'une case quelconque.; in	D5.W	numro de la case;	D4.W	paramtre; out	-; mod	D4.L, D7.WPUTSEL:	PUSHM.L	D3,D4,D5,A4	LOAD.L	A4,#R16"TAINFO	MUL.WU	D5,#10	CLR.L	D3	LOAD.W	D3,(A4)+(D5.W)+8	LOAD.L	A4,#R16"START	ADD.L	A4,D3	CALL	(A4)		; CALL PUT...	CALL	CHECK		; rend le status plausible	POPM.L	D3,D4,D5,A4	RETTAINFO:	.W	0	AFCMY	ASKCMY	GETHTP	PUTHTP	.W	0	AFCMX	ASKCMX	GETLGP	PUTLGP	.W	24	AFCMX	ASKCMX	GETMGG	PUTMGG	.W	24	AFCMX	ASKCMX	GETMGD	PUTMGD	.W	48	AFCMY	ASKCMY	GETMGS	PUTMGS	.W	48	AFCMY	ASKCMY	GETMGI	PUTMGI	.W	48/4	AFMMY	ASKMMY	GETITL	PUTITL	.W	24/4	AFMMX	ASKMMX	GETITC	PUTITC	.W	10	AFNB	ASKNB	GETNBL	PUTNBL	.W	10	AFNB	ASKNB	GETNBC	PUTNBC;--------\; GET...  >;--------/; in	-; out	D4.W	paramtre; mod	D4.LGETHTP:	LOAD.W	D4,(A6)+OBUSTP+OPRHTP	RETGETMGS:	LOAD.W	D4,(A6)+OBUSTP+OPRMGS	RETGETMGI:	LOAD.W	D4,(A6)+OBUSTP+OPRMGI	RETGETITL:	LOAD.W	D4,(A6)+OBUSTP+OPRITL	RETGETNBL:	CLR.L	D4	LOAD.W	D4,(A6)+OBUSTP+OPRHTP	SUB.W	D4,(A6)+OBUSTP+OPRMGS	SUB.W	D4,(A6)+OBUSTP+OPRMGI	DIV.WU	D4,(A6)+OBUSTP+OPRITL	RETGETLGP:	LOAD.W	D4,(A6)+OBUSTP+OPRLGP	RETGETMGG:	LOAD.W	D4,(A6)+OBUSTP+OPRMGG	RETGETMGD:	LOAD.W	D4,(A6)+OBUSTP+OPRMGD	RETGETITC:	LOAD.W	D4,(A6)+OBUSTP+OPRITC	RETGETNBC:	CLR.L	D4	LOAD.W	D4,(A6)+OBUSTP+OPRLGP	SUB.W	D4,(A6)+OBUSTP+OPRMGG	SUB.W	D4,(A6)+OBUSTP+OPRMGD	DIV.WU	D4,(A6)+OBUSTP+OPRITC	RETGETFON:	LOAD.B	D4,(A6)+OBUSTP+OPRFON	RETGETSTY:	LOAD.B	D4,(A6)+OBUSTP+OPRSTY	RETGETTAI:	LOAD.W	D4,(A6)+OBUSTP+OPRITC	RET;--------\; PUT...  >;--------/; in	D4.W	paramtre; out	-; mod	D4.LPUTHTP:	LOAD.W	(A6)+OBUSTP+OPRHTP,D4	RETPUTMGS:	LOAD.W	(A6)+OBUSTP+OPRMGS,D4	RETPUTMGI:	LOAD.W	(A6)+OBUSTP+OPRMGI,D4	RETPUTITL:	TEST.W	D4	JUMP,NE	10$	INC.W	D4		; D4 <-- au moins un10$:	LOAD.W	(A6)+OBUSTP+OPRITL,D4	RETPUTNBL:	TEST.W	D4	JUMP,NE	10$	INC.W	D4		; D4 <-- au moins une ligne10$:	PUSH.L	D3	CLR.L	D3	LOAD.W	D3,(A6)+OBUSTP+OPRHTP	SUB.W	D3,(A6)+OBUSTP+OPRMGS	SUB.W	D3,(A6)+OBUSTP+OPRMGI	DIV.WU	D3,D4	LOAD.W	(A6)+OBUSTP+OPRITL,D3	POP.L	D3	RETPUTLGP:	LOAD.W	(A6)+OBUSTP+OPRLGP,D4	RETPUTMGG:	LOAD.W	(A6)+OBUSTP+OPRMGG,D4	RETPUTMGD:	LOAD.W	(A6)+OBUSTP+OPRMGD,D4	RETPUTITC:	TEST.W	D4	JUMP,NE	10$	INC.W	D4		; D4 <-- au moins un10$:	LOAD.W	(A6)+OBUSTP+OPRITC,D4	RETPUTNBC:	TEST.W	D4	JUMP,NE	10$	INC.W	D4		; D4 <-- au moins un caractre10$:	PUSH.L	D3	CLR.L	D3	LOAD.W	D3,(A6)+OBUSTP+OPRLGP	SUB.W	D3,(A6)+OBUSTP+OPRMGG	SUB.W	D3,(A6)+OBUSTP+OPRMGD	DIV.WU	D3,D4	LOAD.W	(A6)+OBUSTP+OPRITC,D3	POP.L	D3	RETPUTFON:	LOAD.B	(A6)+OBUSTP+OPRFON,D4	RETPUTSTY:	LOAD.B	(A6)+OBUSTP+OPRSTY,D4	RETPUTTAI:	LOAD.W	(A6)+OBUSTP+OPRITC,D4	RET	.END